import { useEffect, useMemo, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuthStore } from '@/store/useAuthStore'
import {
  loadVerbs, loadVerbProgress,
  TENSES, TENSE_LABEL, hasUsableTense,
  type Tense, type VerbRow, type VerbProgress, type TenseMastery
} from '@/lib/verbs'
import { Header } from '@/components/Header'
import { BottomNav } from '@/components/BottomNav'

// VerbTrainer-Hub laut CLAUDE.md §6.7
//   - Tempus-Auswahl (5 Pills)
//   - Verb-Liste mit Mastery-Heatmap (5 Zellen pro Verb: ⬜ noch nichts / 🟨 angefangen / 🟩 gemeistert)
//   - 5 Modus-Buttons darunter, jeweils geöffnet mit aktuell gewähltem Tempus
//
// Filter-Bar wird hier bewusst nicht gezeigt — Verben sind ein eigener Datensatz,
// die Vokabel-Filter (Kategorie etc.) greifen nicht.

const SUBMODES: Array<{ id: string; emoji: string; title: string; xp: string; available: boolean; path: string }> = [
  { id: 'conjugate', emoji: '⌨️', title: 'Konjugation tippen', xp: '+12 XP', available: true,  path: 'conjugate' },
  { id: 'mc',        emoji: '✅', title: 'MC-Konjugation',     xp: '+8 XP',  available: true,  path: 'mc' },
  { id: 'reverse',   emoji: '🔍', title: 'Form erkennen',       xp: '+15 XP', available: true,  path: 'reverse' },
  { id: 'table',     emoji: '🔢', title: 'Tempus-Tabelle',      xp: '+30 XP', available: true,  path: 'table' },
  { id: 'cloze',     emoji: '✏️',  title: 'Lückentext',          xp: '+18 XP', available: true,  path: 'cloze' }
]

export default function VerbTrainer() {
  const { user } = useAuthStore()
  const navigate = useNavigate()
  const [tense, setTense] = useState<Tense>('present_indefinite')
  const [verbs, setVerbs] = useState<VerbRow[] | null>(null)
  const [progress, setProgress] = useState<Map<number, VerbProgress>>(new Map())
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!user) return
    let cancelled = false
    async function load() {
      try {
        const [v, p] = await Promise.all([loadVerbs(), loadVerbProgress(user!.id)])
        if (cancelled) return
        setVerbs(v)
        setProgress(p)
      } catch (e) {
        setError(String((e as Error).message ?? e))
      }
    }
    void load()
    return () => { cancelled = true }
  }, [user])

  const usableVerbs = useMemo(() => {
    if (!verbs) return []
    // Verben ohne ein einziges nicht-null Feld → komplett aus dem Hub raus.
    return verbs.filter((v) => TENSES.some((t) => hasUsableTense(v, t)))
  }, [verbs])

  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', paddingBottom: 90 }}>
      <Header />
      <main className="app-container">
        <h1 className="app-name" style={{ color: 'var(--red)', margin: 0, fontSize: '1.45rem' }}>
          Verbentrainer ⚡
        </h1>
        <p style={{ opacity: 0.65, margin: 0, fontSize: '0.88rem' }}>
          {usableVerbs.length} Verben · 5 Tempora · Mastery pro Tempus
        </p>

        {/* Tempus-Pills */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
          {TENSES.map((t) => (
            <button
              key={t}
              onClick={() => setTense(t)}
              style={{
                padding: '0.45rem 0.8rem',
                borderRadius: 999,
                border: `1.5px solid var(--green)`,
                background: t === tense ? 'var(--green)' : 'transparent',
                color: t === tense ? 'var(--cream)' : 'var(--green)',
                fontFamily: 'inherit',
                fontWeight: 600,
                fontSize: '0.8rem',
                cursor: 'pointer'
              }}
            >
              {TENSE_LABEL[t]}
            </button>
          ))}
        </div>

        {/* Modus-Buttons */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: 8 }}>
          {SUBMODES.map((m) => (
            <button
              key={m.id}
              disabled={!m.available}
              onClick={() => navigate(`/learn/medical/verb-trainer/${m.path}?tense=${tense}`)}
              style={{
                background: 'var(--white)',
                border: '2px solid var(--red)',
                borderRadius: 12,
                padding: '0.85rem',
                cursor: m.available ? 'pointer' : 'default',
                opacity: m.available ? 1 : 0.5,
                fontFamily: 'inherit',
                textAlign: 'left',
                boxShadow: 'var(--shadow-card)'
              }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <span style={{ fontSize: '1.4rem' }}>{m.emoji}</span>
                <span style={{ fontFamily: 'Georgia, serif', fontWeight: 700, color: 'var(--red)', flex: 1 }}>{m.title}</span>
                <span style={{ fontSize: '0.7rem', opacity: 0.65, fontWeight: 600 }}>{m.xp}</span>
              </div>
            </button>
          ))}
        </div>

        {/* Mastery-Heatmap */}
        <h2 style={{ fontFamily: 'Georgia, serif', fontSize: '0.85rem', letterSpacing: '1px', textTransform: 'uppercase', opacity: 0.6, margin: '0.5rem 0 0' }}>
          Mastery-Übersicht
        </h2>
        {error && <div style={{ color: 'var(--red)', fontSize: '0.85rem' }}>⚠ {error}</div>}
        {!verbs && !error && <div style={{ opacity: 0.55, fontSize: '0.85rem' }}>Wird geladen…</div>}
        {usableVerbs.length > 0 && (
          <div
            style={{
              background: 'var(--white)',
              border: '2px solid var(--green)',
              borderRadius: 12,
              padding: '0.6rem',
              boxShadow: 'var(--shadow-card)',
              overflowX: 'auto'
            }}
          >
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.78rem' }}>
              <thead>
                <tr>
                  <th style={th()}>Verb</th>
                  {TENSES.map((t) => (
                    <th key={t} style={th()} title={TENSE_LABEL[t]}>{tenseShort(t)}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {usableVerbs.map((v) => {
                  const p = progress.get(v.id)
                  return (
                    <tr key={v.id}>
                      <td style={tdLemma()}>
                        <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, color: 'var(--red)' }}>{v.infinitive}</div>
                        <div style={{ fontSize: '0.7rem', opacity: 0.6 }}>{v.infinitive_de}</div>
                      </td>
                      {TENSES.map((t) => {
                        const m = p?.mastery?.[t]
                        const usable = hasUsableTense(v, t)
                        return (
                          <td key={t} style={tdCell()}>
                            <MasteryCell mastery={m} disabled={!usable} />
                          </td>
                        )
                      })}
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        )}
      </main>
      <BottomNav />
    </div>
  )
}

function MasteryCell({ mastery, disabled }: { mastery: TenseMastery | undefined; disabled: boolean }) {
  if (disabled) return <span style={{ opacity: 0.25 }}>—</span>
  if (!mastery) return <span title="noch nicht versucht" style={{ opacity: 0.45 }}>⬜</span>
  if (mastery.mastered_at) return <span title={`Gemeistert (${mastery.correct}/${mastery.correct + mastery.wrong})`}>🟩</span>
  if (mastery.streak > 0 || mastery.correct > 0) return <span title={`Streak ${mastery.streak} · ${mastery.correct} richtig / ${mastery.wrong} falsch`}>🟨</span>
  return <span title={`${mastery.wrong} falsch`}>⬜</span>
}

function tenseShort(t: Tense): string {
  return {
    present_indefinite: 'Präs',
    past_indefinite: 'Vgh',
    conditional_present: 'Kond',
    imperative: 'Imp',
    future_periphrastic: 'Zuk'
  }[t]
}

function th(): React.CSSProperties {
  return { textAlign: 'left', padding: '0.45rem 0.5rem', fontWeight: 700, fontFamily: 'Georgia, serif', fontSize: '0.72rem', opacity: 0.65, borderBottom: '1px solid rgba(0,0,0,0.08)' }
}
function tdLemma(): React.CSSProperties {
  return { padding: '0.45rem 0.5rem', borderBottom: '1px solid rgba(0,0,0,0.05)' }
}
function tdCell(): React.CSSProperties {
  return { padding: '0.45rem 0.5rem', textAlign: 'center', borderBottom: '1px solid rgba(0,0,0,0.05)', fontSize: '1.1rem' }
}
